use soroban_sdk::{Address,Env,Vec};use crate::types::*;use common::pause;
pub fn init(env:&Env,admin:&Address){admin.require_auth();env.storage().instance().set(&DataKey::Admin,admin);}
pub fn record(env:&Env,user:&Address,t:u32,impact:u32)->Result<(),ReputationError>{pause::when_not_paused(env).map_err(|_|ReputationError::ContractPaused)?;user.require_auth();if t>ACTIVITY_PAYOUT_RECEIVED{return Err(ReputationError::InvalidActivityType);}if impact>1000{return Err(ReputationError::InvalidScoreImpact);}let now=env.ledger().timestamp();let mut score=env.storage().persistent().get(&DataKey::Scores).unwrap_or_else(||MoiScore{user:user.clone(),score:0,tier:TIER_BRONZE,total_circles:0,completed_circles:0,defaulted_circles:0,streak_count:0,last_activity_at:now,updated_at:now});let old=score.score;let ns=score.score.saturating_add(impact);score.score=if ns>1000{1000}else{ns};match t{ACTIVITY_JOIN=>{score.total_circles=score.total_circles.wrapping_add(1);}ACTIVITY_CONTRIBUTE=>{score.streak_count=score.streak_count.wrapping_add(1);}ACTIVITY_COMPLETE=>{score.completed_circles=score.completed_circles.wrapping_add(1);}ACTIVITY_DEFAULT=>{score.defaulted_circles=score.defaulted_circles.wrapping_add(1);score.streak_count=0;}_=>{}}score.tier=if score.score>=800{TIER_DIAMOND}else if score.score>=600{TIER_PLATINUM}else if score.score>=400{TIER_GOLD}else if score.score>=200{TIER_SILVER}else{TIER_BRONZE};score.last_activity_at=now;score.updated_at=now;env.storage().persistent().set(&DataKey::Scores,&score);let mut acts:Vec<Activity>=env.storage().persistent().get(&DataKey::Activity).unwrap_or_else(||Vec::new(env));acts.push_back(Activity{user:user.clone(),activity_type:t,score_impact:impact,timestamp:now});env.storage().persistent().set(&DataKey::Activity,&acts);ActivityRecorded{user:user.clone(),activity_type:t,score_impact:impact,new_score:score.score}.publish(env);if old!=score.score{ScoreUpdated{user:user.clone(),old_score:old,new_score:score.score,tier:score.tier}.publish(env);}Ok(())}
pub fn get_score(env:&Env,u:&Address)->MoiScore{env.storage().persistent().get(&DataKey::Scores).unwrap_or_else(||MoiScore{user:u.clone(),score:0,tier:TIER_BRONZE,total_circles:0,completed_circles:0,defaulted_circles:0,streak_count:0,last_activity_at:0,updated_at:0})}
pub fn get_history(env:&Env,user:&Address)->Vec<Activity>{let all:Vec<Activity>=env.storage().persistent().get(&DataKey::Activity).unwrap_or_else(||Vec::new(env));let mut out=Vec::new(env);for i in 0..all.len(){if let Some(a)=all.get(i){if a.user==*user{out.push_back(a);}}}out}
pub fn pause(env:&Env,a:&Address)->Result<(),ReputationError>{let s:Address=env.storage().instance().get(&DataKey::Admin).ok_or(ReputationError::NotInitialized)?;if a!=&s{return Err(ReputationError::Unauthorized);}pause::pause(env,a).map_err(|_|ReputationError::ContractPaused)}
pub fn unpause(env:&Env,a:&Address)->Result<(),ReputationError>{let s:Address=env.storage().instance().get(&DataKey::Admin).ok_or(ReputationError::NotInitialized)?;if a!=&s{return Err(ReputationError::Unauthorized);}pause::unpause(env,a).map_err(|_|ReputationError::ContractPaused)}
